create extension if not exists "uuid-ossp";
create type complaint_status as enum ('submitted','acknowledged','assigned','in_progress','resolved','closed','rejected');
create type complaint_priority as enum ('low','medium','high','critical');
create table public.users(id uuid primary key references auth.users(id) on delete cascade, full_name text not null, phone text, role text not null default 'consumer' check(role in('consumer','admin','engineer')), avatar_url text, address text, created_at timestamptz default now(), updated_at timestamptz default now());
create table public.engineers(id uuid primary key default uuid_generate_v4(), user_id uuid references public.users(id), name text not null, phone text not null, department text not null, service_area text not null, active boolean default true, rating numeric default 5, created_at timestamptz default now());
create table public.complaints(id uuid primary key default uuid_generate_v4(), user_id uuid not null references public.users(id) on delete cascade, assigned_engineer_id uuid references public.engineers(id), title text not null, description text not null, category text not null, priority complaint_priority not null, severity int not null check(severity between 1 and 10), status complaint_status not null default 'submitted', department text not null, address text not null, lat double precision, lng double precision, ai_summary text not null, engineer_brief text not null, duplicate_of uuid references public.complaints(id), confidence numeric not null default 0, created_at timestamptz default now(), updated_at timestamptz default now(), resolved_at timestamptz);
create table public.images(id uuid primary key default uuid_generate_v4(), complaint_id uuid not null references public.complaints(id) on delete cascade, url text not null, analysis jsonb default '{}'::jsonb, created_at timestamptz default now());
create table public.notifications(id uuid primary key default uuid_generate_v4(), user_id uuid not null references public.users(id) on delete cascade, complaint_id uuid references public.complaints(id) on delete cascade, title text not null, body text not null, channel text not null default 'email', read_at timestamptz, created_at timestamptz default now());
create table public.status_logs(id uuid primary key default uuid_generate_v4(), complaint_id uuid not null references public.complaints(id) on delete cascade, status complaint_status not null, note text, changed_by uuid references public.users(id), created_at timestamptz default now());
create table public.analytics(id uuid primary key default uuid_generate_v4(), metric_date date not null, metric_name text not null, metric_value numeric not null, dimensions jsonb default '{}'::jsonb, unique(metric_date, metric_name, dimensions));
create index complaints_user_idx on public.complaints(user_id, created_at desc);create index complaints_status_idx on public.complaints(status);create index complaints_priority_idx on public.complaints(priority);create index complaints_geo_idx on public.complaints(lat,lng);create index complaints_search_idx on public.complaints using gin(to_tsvector('english', title||' '||description||' '||address));
create or replace function public.touch_updated_at() returns trigger language plpgsql as $$ begin new.updated_at=now(); return new; end $$;
create trigger users_touch before update on public.users for each row execute function public.touch_updated_at();create trigger complaints_touch before update on public.complaints for each row execute function public.touch_updated_at();
alter table public.users enable row level security;alter table public.complaints enable row level security;alter table public.images enable row level security;alter table public.notifications enable row level security;alter table public.engineers enable row level security;alter table public.status_logs enable row level security;alter table public.analytics enable row level security;
create policy users_self on public.users for all using(auth.uid()=id) with check(auth.uid()=id);
create policy complaints_owner_read on public.complaints for select using(auth.uid()=user_id or exists(select 1 from public.users u where u.id=auth.uid() and u.role in('admin','engineer')));
create policy complaints_owner_insert on public.complaints for insert with check(auth.uid()=user_id);
create policy complaints_admin_update on public.complaints for update using(exists(select 1 from public.users u where u.id=auth.uid() and u.role in('admin','engineer')));
create policy images_related on public.images for select using(exists(select 1 from public.complaints c where c.id=complaint_id and (c.user_id=auth.uid() or exists(select 1 from public.users u where u.id=auth.uid() and u.role in('admin','engineer')))));
create policy notifications_owner on public.notifications for all using(auth.uid()=user_id);
create policy admin_all_engineers on public.engineers for all using(exists(select 1 from public.users u where u.id=auth.uid() and u.role='admin'));
create policy status_visible on public.status_logs for select using(exists(select 1 from public.complaints c where c.id=complaint_id and (c.user_id=auth.uid() or exists(select 1 from public.users u where u.id=auth.uid() and u.role in('admin','engineer')))));
create policy analytics_admin on public.analytics for select using(exists(select 1 from public.users u where u.id=auth.uid() and u.role='admin'));
